const GoToUserDoc = () => {
  const path = window.location.origin
  const url = path + '/doc'
  fetch(url, {
    method: 'GET'
  }).then((response) => {
    if (response.redirected) {
      return window.open(response.url, '_blank')
    }
  }).then(win => win?.focus())
}

